class Solution:
    def maxProduct(self, words):
        sets = [set(w) for w in words]
        best = 0
        n = len(words)
        for i in range(n):
            for j in range(i + 1, n):
                if not (sets[i] & sets[j]):
                    best = max(best, len(words[i]) * len(words[j]))
        return best

