class Solution:
    def maxProduct(self, words):
        masks = []
        for w in words:
            m = 0
            for ch in w:
                m |= 1 << (ord(ch) - 97)
            masks.append(m)
        best = 0
        n = len(words)
        for i in range(n):
            for j in range(i + 1, n):
                if masks[i] & masks[j] == 0:
                    p = len(words[i]) * len(words[j])
                    if p > best:
                        best = p
        return best

