var maxProduct = function(words) {
    const n = words.length;
    const masks = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        let m = 0;
        for (const ch of words[i]) m |= 1 << (ch.charCodeAt(0) - 97);
        masks[i] = m;
    }
    let best = 0;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            if ((masks[i] & masks[j]) === 0) {
                const p = words[i].length * words[j].length;
                if (p > best) best = p;
            }
        }
    }
    return best;
};
